import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";
import { FacilityData, ManualInputs } from "../types/facility";

// Keep the base64 logo isolated here so it doesn't clutter page.tsx
const LOGO_BASE64 =
  "data:image/png;base64,";

function buildTableRows(
  apiData: FacilityData,
  inputs: ManualInputs,
  finalName: string,
): string[][] {
  return [
    ["Name of Facility", finalName],
    ["Location", apiData.location],
    ["EMR", inputs.emr],
    ["Census Capacity", apiData.census_capacity ?? ""],
    ["Current Census", inputs.currentCensus],
    ["Type of Patient", inputs.patientType],
    ["Previous Coverage from Medelite", inputs.prevCoverage],
    ["Previous Provider Performance from Medelite", inputs.prevPerformance],
    ["Medical Coverage", inputs.medicalCoverage],
    ["Overall Star Rating", apiData.star_ratings.overall ?? ""],
    ["Health Inspection", apiData.star_ratings.health_inspection ?? ""],
    ["Staffing", apiData.star_ratings.staffing ?? ""],
    ["Quality of Resident Care", apiData.star_ratings.quality_care ?? ""],
    ["Short Term Hospitalization", apiData.claims_metrics.short_term_hospitalization ?? ""],
    [
      "STR National Avg. for Hospitalization",
      apiData.claims_metrics.str_national_avg_hospitalization ?? "",
    ],
    [
      "STR State Avg. for Hospitalization",
      apiData.claims_metrics.str_state_avg_hospitalization ?? "",
    ],
    ["STR ED Visit", apiData.claims_metrics.str_ed_visit ?? ""],
    ["STR ED Visits National Avg.", apiData.claims_metrics.str_ed_visits_national_avg ?? ""],
    ["STR ED Visits State Avg.", apiData.claims_metrics.str_ed_visits_state_avg ?? ""],
    ["LT Hospitalization", apiData.claims_metrics.lt_hospitalization ?? ""],
    [
      "LT National Avg. for Hospitalization",
      apiData.claims_metrics.lt_national_avg_hospitalization ?? "",
    ],
    [
      "LT State Avg. for Hospitalization",
      apiData.claims_metrics.lt_state_avg_hospitalization ?? "",
    ],
    ["LT ED Visit", apiData.claims_metrics.lt_ed_visit ?? ""],
    ["LT ED Visits National Avg.", apiData.claims_metrics.lt_ed_visits_national_avg ?? ""],
    ["LT ED Visits State Avg.", apiData.claims_metrics.lt_ed_visits_state_avg ?? ""],
  ];
}

export function generatePDF(apiData: FacilityData, inputs: ManualInputs, ccn: string) {
  const doc = new jsPDF();
  const finalName = inputs.nameOverride || apiData.name_of_facility || "";
  const dynamicLink = `https://www.medicare.gov/care-compare/details/nursing-home/${ccn}`;

  const pageWidth = doc.internal.pageSize.getWidth();
  const center = pageWidth / 2;

  // Logo
  const imgWidth = 90;
  const imgHeight = 22;
  doc.addImage(LOGO_BASE64, "PNG", center - imgWidth / 2, 15, imgWidth, imgHeight);

  // Header
  doc.setFontSize(13);
  doc.setFont("helvetica", "bold");
  doc.text("INFINITE — Managed by MEDELITE", center, 44, { align: "center" });
  doc.text("FACILITY ASSESSMENT SNAPSHOT", center, 51, { align: "center" });
  doc.text(apiData.state_code, center, 58, { align: "center" });

  // Table
  autoTable(doc, {
    startY: 60,
    body: buildTableRows(apiData, inputs, finalName),
    theme: "grid",
    styles: { fontSize: 11, cellPadding: 4, textColor: [0, 0, 0] },
    columnStyles: {
      0: { fontStyle: "bold", cellWidth: 85 },
      1: { cellWidth: "auto" },
    },
  });

  // Hyperlink
  const finalY = (doc as any).lastAutoTable.finalY || 45;
  doc.setTextColor(0, 0, 255);
  doc.textWithLink("View Official Medicare Profile", 14, finalY + 15, {
    url: dynamicLink,
  });

  doc.save(`${finalName}_Assessment.pdf`);
}
